import novamind_api as nm

# Check enterprise opportunities
print('=== ENTERPRISE LEADS & NEGOTIATIONS ===')
result = nm.query('SELECT message_id, customer_id, thread_type, status FROM enterprise_turns ORDER BY message_id DESC LIMIT 20')
if result['rows']:
    for row in result['rows']:
        print(f\"  {row['message_id']}: cid={row['customer_id']}, type={row['thread_type']}, status={row['status']}\")
else:
    print('  (No enterprise turns)')

# Check outage details
print('\n=== SERVICE RELIABILITY ===')
result = nm.query('SELECT day, duration FROM service_day WHERE outage_duration_minutes > 0 ORDER BY day DESC LIMIT 5')
if result['rows']:
    for row in result['rows']:
        print(f\"  Day {row['day']}: Outage for {row['duration']} minutes\")
else:
    print('  (No recorded outages)')
"

