result = nm.query('SELECT day, outage_duration_minutes FROM service_day WHERE outage_duration_minutes > 0 ORDER BY day DESC LIMIT 5')
if result['rows']:
    for row in result['rows']:
        print(f\"  Day {row['day']}: Outage for {row['outage_duration_minutes']} minutes\")
else:
    print('  (No recorded outages)')
