arguments.command:
./novamind-operation python-c "
import novamind_api as nm

# Get current subscriber breakdown (correct status value)
result = nm.query('SELECT c.group_id, COUNT(*) as n FROM subscriptions s JOIN customers c ON s.customer_id = c.customer_id WHERE s.status=\"subscribed\" GROUP BY c.group_id ORDER BY n DESC')
print('=== ACTIVE SUBSCRIBERS BY GROUP ===')
if result['rows']:
    for row in result['rows']:
        print(f\"{row['group_id']}: {row['n']}\")
else:
    print('No results')

print('\n=== MARKET OVERVIEW ===')
try:
    overview = nm.market.get_market_overview()
    print(f'Overview keys: {overview.keys()}')
    if 'group_insights' in overview:
        print(f'Groups: {len(overview[\"group_insights\"])}')
        for group_id, insights in list(overview['group_insights'].items())[:15]:
            disc = insights.get('discovered', False)
            info_level = insights.get('info_level', 0)
            print(f\"  {group_id}: info_level={info_level}, discovered={disc}\")
except Exception as e:
    print(f'Error: {e}')
"

